import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import WelcomeScreen from './components/WelcomeScreen';
import MeetingsScreen from './components/MeetingsScreen';
import MeetingInProgress from './components/MeetingInProgress';
import ClientAdmin from './components/ClientAdmin';
import SplashScreen from './components/SplashScreen';
import axios from 'axios';
import './App.css';

// Set base URL for API - connects to workplace server on port 5001
axios.defaults.baseURL = process.env.REACT_APP_API_URL || 'http://localhost:5001/api';

// Add response interceptor for error handling
axios.interceptors.response.use(
  response => response,
  error => {
    console.error('API Error:', error.response?.status, error.response?.data || error.message);
    if (error.code === 'ECONNREFUSED') {
      console.error('❌ Cannot connect to backend. Make sure the workplace server is running on port 5001');
    }
    return Promise.reject(error);
  }
);

function AppContent({ config, configLoaded, showSplash, setShowSplash }) {
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    // Always redirect to home on page load/refresh if on /meetings
    if (configLoaded && !showSplash && location.pathname === '/meetings') {
      const wasNavigated = sessionStorage.getItem('meetingsVisited');
      if (!wasNavigated) {
        navigate('/', { replace: true });
      } else {
        // Clear the flag after using it
        sessionStorage.removeItem('meetingsVisited');
      }
    }
  }, [configLoaded, showSplash, location.pathname, navigate]);

  if (!configLoaded || showSplash) {
    if (showSplash) {
      return <SplashScreen onComplete={() => setShowSplash(false)} />;
    }
    return (
      <div className="app-loading">
        <div className="loading-spinner"></div>
        <p>Loading...</p>
      </div>
    );
  }

  return (
    <Routes>
      <Route path="/" element={<WelcomeScreen config={config} />} />
      <Route path="/meetings" element={<MeetingsScreen config={config} />} />
      <Route path="/meetings/:meetingId" element={<MeetingInProgress />} />
      <Route path="/admin" element={<ClientAdmin />} />
      <Route path="*" element={<WelcomeScreen config={config} />} />
    </Routes>
  );
}

function App() {
  const [config, setConfig] = useState(null);
  const [configLoaded, setConfigLoaded] = useState(false);
  const [showSplash, setShowSplash] = useState(true);

  useEffect(() => {
    // Fetch configuration (if you add a config endpoint later)
    // For now, use defaults
    setConfig({
      companyName: process.env.REACT_APP_COMPANY_NAME || 'Your Company',
      logoUrl: '/assets/logo.png',
      welcomeMessage: 'Welcome'
    });
    setConfigLoaded(true);
  }, []);

  if (!configLoaded || showSplash) {
    if (showSplash) {
      return <SplashScreen onComplete={() => setShowSplash(false)} />;
    }
    return (
      <div className="app-loading">
        <div className="loading-spinner"></div>
        <p>Loading...</p>
      </div>
    );
  }

  return (
    <Router>
      <div className="App">
        <AppContent config={config} configLoaded={configLoaded} showSplash={showSplash} setShowSplash={setShowSplash} />
      </div>
    </Router>
  );
}

export default App;
